import java.util.*;
public class Solution {
    public static void main(String[] args) {
        String s = "Anamika and Suman are never going to quarrel anymore";
        String vowels = "aeiouAEIOU";
        String[] words = s.split(" ");
        List<String> vowelWords = new ArrayList<>();
