public class Solution {
    public static void main(String[] args) {
        int n = 153, original = 153, sum = 0;
        int digits = String.valueOf(n).length();
        int temp = n;
        while (temp > 0) {
            int d = temp % 10;
            sum += Math.pow(d, digits);
            temp /= 10;
        }
        System.out.println(n + (sum == original ? " is an Armstrong number" : " is not an Armstrong number"));
    }
}

