import java.util.*;
public class Solution {
    public static void main(String[] args) {
        String str = "ghrrtmhistrabatrhcch";
        Set<String> palindromes = new LinkedHashSet<>();
        for (int i = 0; i < str.length(); i++) {
            for (int j = i + 3; j <= str.length(); j++) {
                String sub = str.substring(i, j);
                if (sub.equals(new StringBuilder(sub).reverse().toString())) palindromes.add(sub);
            }
        }
        System.out.println(palindromes.isEmpty() ? "no palindrome substrings found" : String.join(", ", palindromes));
    }
}

